export const getMonsterNaturalStars = (monsterId: number): number | undefined => NATURAL_STARS_BY_CANONICAL_ID[monsterId];

export const getMonsterElement = (monsterId: number): "water" | "fire" | "wind" | "light" | "dark" | undefined => {
  switch (monsterId % 10) {
    case 1: return "water";
    case 2: return "fire";
    case 3: return "wind";
    case 4: return "light";
    case 5: return "dark";
    default: return undefined;
  }
};